--
-- Table structure for table `flights_shown`
--

DROP TABLE IF EXISTS `flights_shown`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `flights_shown` (
  `id` int NOT NULL AUTO_INCREMENT,
  `search_id` int NOT NULL,
  `flight_data` json NOT NULL,
  `display_position` int DEFAULT NULL,
  `algorithm` varchar(100) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `ix_flights_shown_search_id` (`search_id`),
  CONSTRAINT `flights_shown_ibfk_1` FOREIGN KEY (`search_id`) REFERENCES `searches` (`search_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=164 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
